#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord)]
struct PlacedTrackedInputKey {
    agent_identity: String,
    host_id: String,
    generation: u64,
    fence_token: u64,
    input_id: String,
}

impl PlacedTrackedInputKey {
    fn completion(obligation: &crate::event::PlacedCompletionObligationEvent) -> Self {
        Self {
            agent_identity: obligation.agent_identity.to_string(),
            host_id: obligation.host_id.clone(),
            generation: obligation.generation.get(),
            fence_token: obligation.fence_token.get(),
            input_id: obligation.input_id.clone(),
        }
    }

    fn remote_turn(obligation: &crate::event::RemoteTurnObligationEvent) -> Self {
        Self {
            agent_identity: obligation.agent_identity.to_string(),
            host_id: obligation.host_id.clone(),
            generation: obligation.generation.get(),
            fence_token: obligation.fence_token.get(),
            input_id: obligation.input_id.clone(),
        }
    }

    fn kickoff(obligation: &crate::event::PlacedKickoffObligationEvent) -> Self {
        Self {
            agent_identity: obligation.agent_identity.to_string(),
            host_id: obligation.host_id.clone(),
            generation: obligation.generation.get(),
            fence_token: obligation.fence_token.get(),
            input_id: obligation.input_id.clone(),
        }
    }
}

#[derive(Debug, Default)]
pub(super) struct PlacedCompletionDurableIndex {
    used_tracked_inputs: BTreeMap<PlacedTrackedInputKey, PlacedTrackedInputOwner>,
    // Private remote-turn intents are the replay-complete authority. Keep
    // their TurnKeys separately so an actor-local index rebuild after an
    // ambiguous public append cannot forget a key whose Record projection is
    // still missing.
    private_remote_turns: BTreeMap<PlacedTrackedInputKey, crate::event::RemoteTurnObligationEvent>,
    completion_phase_events: BTreeMap<(u64, u8), MobEventKind>,
    completion_sequences: BTreeMap<u64, crate::event::PlacedCompletionObligationEvent>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
enum PlacedTrackedInputOwner {
    RemoteTurn(crate::event::RemoteTurnObligationEvent),
    Kickoff(crate::event::PlacedKickoffObligationEvent),
    Completion(crate::event::PlacedCompletionObligationEvent),
}

impl PlacedCompletionDurableIndex {
    pub(super) fn recover(
        events: &[crate::event::MobEvent],
        mob_id: &MobId,
    ) -> Result<Self, MobError> {
        let mut index = Self::default();
        let mut durable_records = BTreeSet::<PlacedTrackedInputKey>::new();
        for event in events.iter().filter(|event| &event.mob_id == mob_id) {
            if matches!(event.kind, MobEventKind::MobReset) {
                // Used host keys remain reserved across reset; phase sequence
                // idempotency is scoped to the current machine epoch.
                index.completion_phase_events.clear();
                index.completion_sequences.clear();
                continue;
            }
            let record_key = match &event.kind {
                MobEventKind::RemoteTurnObligationRecorded { obligation } => {
                    Some(PlacedTrackedInputKey::remote_turn(obligation))
                }
                MobEventKind::PlacedKickoffObligationRecorded { obligation } => {
                    Some(PlacedTrackedInputKey::kickoff(obligation))
                }
                MobEventKind::PlacedCompletionObligationRecorded { obligation } => {
                    Some(PlacedTrackedInputKey::completion(obligation))
                }
                _ => None,
            };
            if let Some(record_key) = record_key
                && !durable_records.insert(record_key.clone())
            {
                return Err(MobError::Internal(format!(
                    "exact placed host TurnKey '{}' has multiple durable Record carriers",
                    record_key.input_id
                )));
            }
            index.observe(&event.kind)?;
        }
        Ok(index)
    }

    pub(super) fn recover_with_private_remote_turns(
        events: &[crate::event::MobEvent],
        mob_id: &MobId,
        private_remote_turns: &[crate::event::RemoteTurnObligationEvent],
    ) -> Result<Self, MobError> {
        let mut index = Self::recover(events, mob_id)?;
        for obligation in private_remote_turns {
            index.observe_private_remote_turn(obligation.clone())?;
        }
        Ok(index)
    }

    fn observe_private_remote_turn(
        &mut self,
        obligation: crate::event::RemoteTurnObligationEvent,
    ) -> Result<(), MobError> {
        let key = PlacedTrackedInputKey::remote_turn(&obligation);
        self.observe_tracked_input(
            key.clone(),
            PlacedTrackedInputOwner::RemoteTurn(obligation.clone()),
        )?;
        match self.private_remote_turns.get(&key) {
            Some(existing) if existing != &obligation => Err(MobError::Internal(format!(
                "exact placed host TurnKey '{}' has conflicting private remote-turn owners",
                key.input_id
            ))),
            Some(_) => Ok(()),
            None => {
                self.private_remote_turns.insert(key, obligation);
                Ok(())
            }
        }
    }

    fn rebuild_from_events(
        &mut self,
        events: &[crate::event::MobEvent],
        mob_id: &MobId,
    ) -> Result<(), MobError> {
        let private_remote_turns = self
            .private_remote_turns
            .values()
            .cloned()
            .collect::<Vec<_>>();
        *self = Self::recover_with_private_remote_turns(events, mob_id, &private_remote_turns)?;
        Ok(())
    }

    fn phase(kind: &MobEventKind) -> Option<(u8, &crate::event::PlacedCompletionObligationEvent)> {
        match kind {
            MobEventKind::PlacedCompletionObligationRecorded { obligation } => {
                Some((0, obligation))
            }
            MobEventKind::PlacedCompletionCancellationRequested { obligation } => {
                Some((1, obligation))
            }
            MobEventKind::PlacedCompletionOutcomeResolved { obligation, .. } => {
                Some((2, obligation))
            }
            MobEventKind::PlacedCompletionOutcomeClosed { obligation, .. } => Some((3, obligation)),
            MobEventKind::PlacedCompletionOutcomeAcknowledged { obligation } => {
                Some((4, obligation))
            }
            MobEventKind::PlacedCompletionOutcomeDisposed { obligation } => Some((5, obligation)),
            _ => None,
        }
    }

    fn observe(&mut self, kind: &MobEventKind) -> Result<(), MobError> {
        let remote_turn = match kind {
            MobEventKind::RemoteTurnObligationRecorded { obligation }
            | MobEventKind::RemoteTurnOutcomeResolved { obligation }
            | MobEventKind::RemoteTurnOutcomeAcknowledged { obligation }
            | MobEventKind::RemoteTurnOutcomeDisposed { obligation }
            | MobEventKind::StepTargetCompleted {
                remote_turn_obligation: Some(obligation),
                ..
            }
            | MobEventKind::StepTargetFailed {
                remote_turn_obligation: Some(obligation),
                ..
            } => Some(obligation),
            _ => None,
        };
        if let Some(obligation) = remote_turn {
            self.observe_tracked_input(
                PlacedTrackedInputKey::remote_turn(obligation),
                PlacedTrackedInputOwner::RemoteTurn(obligation.clone()),
            )?;
        }
        if let MobEventKind::PlacedKickoffObligationRecorded { obligation } = kind {
            self.observe_tracked_input(
                PlacedTrackedInputKey::kickoff(obligation),
                PlacedTrackedInputOwner::Kickoff(obligation.clone()),
            )?;
        }
        let Some((phase, obligation)) = Self::phase(kind) else {
            return Ok(());
        };
        if phase == 0 {
            self.observe_tracked_input(
                PlacedTrackedInputKey::completion(obligation),
                PlacedTrackedInputOwner::Completion(obligation.clone()),
            )?;
        }
        if let Some(existing) = self.completion_sequences.get(&obligation.dispatch_sequence)
            && existing != obligation
        {
            return Err(MobError::Internal(format!(
                "placed completion durable index has conflicting sequence {}",
                obligation.dispatch_sequence
            )));
        }
        let key = (obligation.dispatch_sequence, phase);
        if let Some(existing) = self.completion_phase_events.get(&key) {
            if existing == kind {
                return Err(MobError::Internal(format!(
                    "placed completion durable index has duplicate phase {phase} sequence {}",
                    obligation.dispatch_sequence
                )));
            }
            return Err(MobError::Internal(format!(
                "placed completion durable index has conflicting phase {phase} sequence {}",
                obligation.dispatch_sequence
            )));
        }
        self.validate_new_phase(obligation.dispatch_sequence, phase)?;
        self.completion_sequences
            .insert(obligation.dispatch_sequence, obligation.clone());
        self.completion_phase_events.insert(key, kind.clone());
        Ok(())
    }

    fn observe_tracked_input(
        &mut self,
        key: PlacedTrackedInputKey,
        owner: PlacedTrackedInputOwner,
    ) -> Result<(), MobError> {
        match self.used_tracked_inputs.get(&key) {
            Some(existing) if existing == &owner => Ok(()),
            Some(_) => Err(MobError::Internal(format!(
                "exact placed host TurnKey '{}' has multiple durable owners",
                key.input_id
            ))),
            None => {
                self.used_tracked_inputs.insert(key, owner);
                Ok(())
            }
        }
    }

    fn reserve_fresh_tracked_input(
        &mut self,
        key: PlacedTrackedInputKey,
        owner: PlacedTrackedInputOwner,
    ) -> Result<(), MobError> {
        if self.used_tracked_inputs.contains_key(&key) {
            return Err(MobError::PlacedInteractionIdAlreadyUsed {
                interaction_id: key.input_id,
            });
        }
        self.used_tracked_inputs.insert(key, owner);
        Ok(())
    }

    fn has_phase(&self, dispatch_sequence: u64, phase: u8) -> bool {
        self.completion_phase_events
            .contains_key(&(dispatch_sequence, phase))
    }

    fn validate_new_phase(&self, dispatch_sequence: u64, phase: u8) -> Result<(), MobError> {
        let missing_record = phase != 0 && !self.has_phase(dispatch_sequence, 0);
        let branch_conflict = match phase {
            // Record must be the first durable carrier in the chain.
            0 => (1..=5).any(|other| self.has_phase(dispatch_sequence, other)),
            // Cancellation is meaningful only before a terminal carrier.
            1 => (2..=5).any(|other| self.has_phase(dispatch_sequence, other)),
            // Resolve and Close are mutually exclusive terminal authorities.
            2 => [3, 4, 5]
                .into_iter()
                .any(|other| self.has_phase(dispatch_sequence, other)),
            3 => [2, 4, 5]
                .into_iter()
                .any(|other| self.has_phase(dispatch_sequence, other)),
            // ACK may only follow Resolve and cannot follow Close/Dispose.
            4 => {
                !self.has_phase(dispatch_sequence, 2)
                    || [3, 5]
                        .into_iter()
                        .any(|other| self.has_phase(dispatch_sequence, other))
            }
            // Exact release may dispose Pending or Resolved custody, but not
            // an already closed or ACK-confirmed chain.
            5 => [3, 4]
                .into_iter()
                .any(|other| self.has_phase(dispatch_sequence, other)),
            _ => true,
        };
        if missing_record || branch_conflict {
            return Err(MobError::Internal(format!(
                "placed completion sequence {dispatch_sequence} has an illegal, predecessor-free, or cross-terminal phase {phase}"
            )));
        }
        Ok(())
    }

    fn desired_present(&self, desired: &MobEventKind) -> Result<bool, MobError> {
        let (phase, obligation) = Self::phase(desired).ok_or_else(|| {
            MobError::Internal("non-completion event queried in completion index".to_string())
        })?;
        if let Some(existing) = self.completion_sequences.get(&obligation.dispatch_sequence)
            && existing != obligation
        {
            return Err(MobError::Internal(format!(
                "placed completion sequence {} conflicts with durable index",
                obligation.dispatch_sequence
            )));
        }
        let present = match self
            .completion_phase_events
            .get(&(obligation.dispatch_sequence, phase))
        {
            Some(existing) if existing == desired => Ok(true),
            Some(_) => Err(MobError::Internal(format!(
                "placed completion phase {phase} sequence {} conflicts with durable index",
                obligation.dispatch_sequence
            ))),
            None => {
                self.validate_new_phase(obligation.dispatch_sequence, phase)?;
                Ok(false)
            }
        }?;
        Ok(present)
    }

    fn require_exact(&self, desired: &MobEventKind) -> Result<(), MobError> {
        if self.desired_present(desired)? {
            Ok(())
        } else {
            let (_, obligation) = Self::phase(desired).ok_or_else(|| {
                MobError::Internal("non-completion event queried in completion index".to_string())
            })?;
            Err(MobError::Internal(format!(
                "placed completion sequence {} has no exact durable replay carrier",
                obligation.dispatch_sequence
            )))
        }
    }
}

/// Lightweight handle for a spawned autonomous initial turn.
///
/// The `JoinHandle` is for abort on stop/dispose.
pub(super) struct InitialTurnHandle {
    handle: tokio::task::JoinHandle<()>,
}

impl InitialTurnHandle {
    /// Abort the in-flight initial turn and await its task so it has fully
    /// stopped before teardown proceeds. The cancellation `JoinError` is
    /// expected and intentionally ignored.
    async fn abort_and_join(self) {
        self.handle.abort();
        let _ = self.handle.await;
    }
}

