pub(super) struct AutonomousStopInterruptIncarnation {
    member_ref: MemberRef,
    expected_member: Option<super::bridge_protocol::BridgeMemberIncarnation>,
}

pub(super) struct AutonomousStopInterruptTask {
    incarnation: AutonomousStopInterruptIncarnation,
    result_rx: oneshot::Receiver<Result<(), MobError>>,
}

/// Typed flag set recording which physical wiring side(s) of a peer-only edge
/// were successfully installed (local recipient, peer recipient, or both).
///
/// Drives best-effort rollback compensation: the wire rollback unwires only the
/// sides that were installed, and the unwire rollback rewires only the sides
/// that had been torn down. Replaces a hand-rolled `&[&str]` of `"local"` /
/// `"peer"` literals re-classified by `.contains(...)`.
#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
struct WiringSides {
    local: bool,
    peer: bool,
}

impl WiringSides {
    /// No sides installed/torn down.
    fn empty() -> Self {
        Self {
            local: false,
            peer: false,
        }
    }

    /// Only the local recipient side.
    fn local() -> Self {
        Self {
            local: true,
            peer: false,
        }
    }

    /// Only the peer recipient side.
    fn peer() -> Self {
        Self {
            local: false,
            peer: true,
        }
    }

    /// Both recipient sides.
    fn both() -> Self {
        Self {
            local: true,
            peer: true,
        }
    }

    fn has_local(self) -> bool {
        self.local
    }

    fn has_peer(self) -> bool {
        self.peer
    }
}

enum SubmitWorkDispatchCompletion {
    Completed,
    AwaitTurnAdmission {
        operation_id: Option<meerkat_core::ops::OperationId>,
        member_ref: MemberRef,
        req: Box<meerkat_core::service::StartTurnRequest>,
        /// `Some(identity)` iff the target is machine-placed on a member
        /// host: a typed delivery failure then fires the W-D.2 revival
        /// trigger back onto the actor.
        placed_identity: Option<AgentIdentity>,
        /// Exact MobMachine-owned incarnation for a placed ingress-accepted
        /// delivery. The host must never receive an unscoped
        /// `expected_member: None` payload for a placed member.
        placed_incarnation: Option<super::bridge_protocol::BridgeMemberIncarnation>,
        /// Canonical non-nil retry-stable transport/idempotency id, distinct
        /// from the optional caller transcript identity.
        placed_input_id: Option<String>,
    },
    AwaitTurnCompletion {
        member_ref: MemberRef,
        req: Box<meerkat_core::service::StartTurnRequest>,
        /// See [`Self::AwaitTurnAdmission::placed_identity`].
        placed_identity: Option<AgentIdentity>,
        /// Exact MobMachine-owned incarnation for the placed completion
        /// delivery. This keeps non-command callers on the explicit remote
        /// transport instead of falling through `start_turn`'s Some=>local
        /// provisioner arm.
        placed_incarnation: Option<super::bridge_protocol::BridgeMemberIncarnation>,
        /// Canonical non-nil interaction/input id shared by the waiter,
        /// runtime transcript identity, host dedup key, and durable cleanup.
        placed_input_id: Option<String>,
        /// Machine-owned Record that was durably committed before the
        /// authoritative SubmitWork ingress transition.
        placed_completion_obligation: Option<crate::event::PlacedCompletionObligationEvent>,
        /// Exact active pump context captured before Record/SubmitWork.
        placed_completion_context: Option<super::event_pump::RemoteCompletionContext>,
    },
}

impl SubmitWorkDispatchCompletion {
    fn kind(&self) -> &'static str {
        match self {
            Self::Completed => "Completed",
            Self::AwaitTurnAdmission { .. } => "AwaitTurnAdmission",
            Self::AwaitTurnCompletion { .. } => "AwaitTurnCompletion",
        }
    }
}

struct SubmitWorkDispatchRequest {
    content: ContentInput,
    /// Host-attached injected context riding with the work content.
    /// Deliverable on queue-mode turn-driven dispatch (local and remote);
    /// autonomous inbox delivery and steer dispatch reject it fail-closed.
    injected_context: Vec<ContentInput>,
    /// Host-supplied interaction identity for the delivered turn. Stamped
    /// into `RuntimeTurnMetadata.transcript_identity` on turn-driven
    /// dispatch and onto the injected inbox event on autonomous dispatch,
    /// so the committed transcript messages persist the id the host's live
    /// interaction frames carry (mobkit ask-15 addendum).
    interaction_id: Option<meerkat_core::interaction::InteractionId>,
    objective_id: Option<meerkat_core::interaction::ObjectiveId>,
    handling_mode: meerkat_core::types::HandlingMode,
    render_metadata: Option<meerkat_core::types::RenderMetadata>,
    ack_mode: crate::mob_machine::SubmitWorkAckMode,
    operation_id: Option<meerkat_core::ops::OperationId>,
    /// Present only for a placed TurnCompleted dispatch. Its durable Record
    /// already exists; dispatch may realize but must never mint custody.
    placed_completion_obligation: Option<crate::event::PlacedCompletionObligationEvent>,
    /// Exact active pump lease captured during pre-Record preflight.
    placed_completion_context: Option<super::event_pump::RemoteCompletionContext>,
}

struct PreparedPlacedCompletionWait {
    expected_member: super::bridge_protocol::BridgeMemberIncarnation,
    input_id: String,
    waiter: oneshot::Receiver<super::event_pump::RemoteInteractionTerminal>,
    obligation: crate::event::PlacedCompletionObligationEvent,
    handle: MobHandle,
    identity: AgentIdentity,
}

/// Canonical turn-metadata carrier for submit-work delivery: render metadata
/// and the host-supplied transcript interaction identity travel together;
/// an empty pair stays `None` so metadata-less requests keep their shape.
fn submit_work_turn_metadata(
    render_metadata: Option<meerkat_core::types::RenderMetadata>,
    interaction_id: Option<meerkat_core::interaction::InteractionId>,
    objective_id: Option<meerkat_core::interaction::ObjectiveId>,
) -> Option<meerkat_core::lifecycle::run_primitive::RuntimeTurnMetadata> {
    if render_metadata.is_none() && interaction_id.is_none() && objective_id.is_none() {
        return None;
    }
    Some(
        meerkat_core::lifecycle::run_primitive::RuntimeTurnMetadata {
            render_metadata,
            transcript_identity: meerkat_core::types::TranscriptMessageIdentity {
                interaction_id,
                run_id: None,
                objective_id,
            },
            ..Default::default()
        },
    )
}

fn placed_submit_interaction_id(
    supplied: Option<meerkat_core::interaction::InteractionId>,
) -> Result<meerkat_core::interaction::InteractionId, MobError> {
    let interaction_id = supplied.unwrap_or_else(|| {
        meerkat_core::interaction::InteractionId(meerkat_core::time_compat::new_uuid_v7())
    });
    if interaction_id.0.is_nil() {
        return Err(MobError::InvalidPlacedInteractionId {
            interaction_id: interaction_id.0.to_string(),
        });
    }
    Ok(interaction_id)
}

fn placed_turn_supplied_interaction_id(
    req: &meerkat_core::service::StartTurnRequest,
) -> Result<Option<meerkat_core::interaction::InteractionId>, MobError> {
    let interaction_id = req
        .runtime
        .turn_metadata
        .as_ref()
        .and_then(|metadata| metadata.transcript_identity.interaction_id);
    if interaction_id.is_some_and(|interaction_id| interaction_id.0.is_nil()) {
        return Err(MobError::InvalidPlacedInteractionId {
            interaction_id: uuid::Uuid::nil().to_string(),
        });
    }
    Ok(interaction_id)
}

#[cfg(test)]
fn placed_turn_test_request(
    interaction_id: Option<meerkat_core::interaction::InteractionId>,
) -> meerkat_core::service::StartTurnRequest {
    meerkat_core::service::StartTurnRequest {
        injected_context: Vec::new(),
        prompt: ContentInput::Text("test".to_string()),
        system_prompt: None,
        event_tx: None,
        runtime: meerkat_core::service::StartTurnRuntimeSemantics::runtime_metadata(
            submit_work_turn_metadata(None, interaction_id, None).unwrap_or_default(),
        ),
    }
}

#[cfg(test)]
#[test]
fn placed_turn_correlation_reuses_supplied_transcript_interaction_id() {
    let supplied =
        meerkat_core::interaction::InteractionId(uuid::Uuid::from_u128(0x1234_5678_9abc));
    let req = placed_turn_test_request(Some(supplied));
    assert_eq!(
        placed_turn_supplied_interaction_id(&req).expect("supplied interaction id is valid"),
        Some(supplied)
    );
}

#[cfg(test)]
#[test]
fn placed_turn_admission_preserves_absence_while_completion_mints_and_both_reject_nil() {
    assert_eq!(
        placed_turn_supplied_interaction_id(&placed_turn_test_request(None))
            .expect("absent admission identity remains absent"),
        None
    );
    let minted = placed_submit_interaction_id(None)
        .expect("absent completion interaction id mints correlation");
    assert!(!minted.0.is_nil());

    let nil = meerkat_core::interaction::InteractionId(uuid::Uuid::nil());
    assert!(placed_turn_supplied_interaction_id(&placed_turn_test_request(Some(nil))).is_err());
    assert!(placed_submit_interaction_id(Some(nil)).is_err());
}

/// Read the machine-owned kickoff objective without allowing a corrupt
/// persisted UUID to degrade into an unscoped turn.
fn machine_kickoff_objective_id(
    state: &mob_dsl::MobMachineState,
    agent_identity: &AgentIdentity,
) -> Result<Option<meerkat_core::interaction::ObjectiveId>, MobError> {
    state
        .member_kickoff_objective_ids
        .get(&mob_dsl::AgentIdentity::from_domain(agent_identity))
        .map(|raw| {
            uuid::Uuid::parse_str(raw)
                .map(meerkat_core::interaction::ObjectiveId)
                .map_err(|error| {
                    MobError::Internal(format!(
                        "MobMachine stored invalid kickoff objective id '{raw}' for '{agent_identity}': {error}"
                    ))
                })
        })
        .transpose()
}

fn required_machine_kickoff_objective_id(
    state: &mob_dsl::MobMachineState,
    agent_identity: &AgentIdentity,
) -> Result<meerkat_core::interaction::ObjectiveId, MobError> {
    machine_kickoff_objective_id(state, agent_identity)?.ok_or_else(|| {
        MobError::Internal(format!(
            "MobMachine has no kickoff objective id for autonomous member '{agent_identity}'"
        ))
    })
}

fn machine_kickoff_turn_metadata(
    state: &mob_dsl::MobMachineState,
    agent_identity: &AgentIdentity,
) -> Result<Option<meerkat_core::lifecycle::run_primitive::RuntimeTurnMetadata>, MobError> {
    Ok(submit_work_turn_metadata(
        None,
        None,
        Some(required_machine_kickoff_objective_id(
            state,
            agent_identity,
        )?),
    ))
}

#[cfg(feature = "runtime-adapter")]
fn kickoff_resolution_input(
    agent_identity: &AgentIdentity,
    outcome: meerkat_runtime::completion::CompletionOutcome,
) -> mob_dsl::MobMachineInput {
    let member_id = mob_dsl::AgentIdentity::from_domain(agent_identity);
    match outcome {
        meerkat_runtime::completion::CompletionOutcome::Completed(_)
        | meerkat_runtime::completion::CompletionOutcome::CompletedWithoutResult => {
            mob_dsl::MobMachineInput::KickoffResolveStarted { member_id }
        }
        meerkat_runtime::completion::CompletionOutcome::CallbackPending { .. } => {
            mob_dsl::MobMachineInput::KickoffResolveCallbackPending { member_id }
        }
        meerkat_runtime::completion::CompletionOutcome::Cancelled => {
            mob_dsl::MobMachineInput::KickoffCancelRequested { member_id }
        }
        meerkat_runtime::completion::CompletionOutcome::Abandoned { reason: error, .. }
        | meerkat_runtime::completion::CompletionOutcome::AbandonedWithError {
            reason: error,
            ..
        }
        | meerkat_runtime::completion::CompletionOutcome::RuntimeTerminated {
            reason: error, ..
        } => mob_dsl::MobMachineInput::KickoffResolveFailed { member_id, error },
        meerkat_runtime::completion::CompletionOutcome::CompletedWithFinalizationFailure {
            error,
        } => mob_dsl::MobMachineInput::KickoffResolveFailed {
            member_id,
            // Runtime completion deliberately withholds the non-durable result;
            // kickoff must preserve that fail-closed contract too.
            error: error
                .detail
                .unwrap_or_else(|| "turn finalization failed".to_string()),
        },
    }
}

fn unresolved_kickoff_member_ids(
    state: &mob_dsl::MobMachineState,
) -> std::collections::BTreeSet<String> {
    // CallbackPending is an interaction terminal and the kickoff completion
    // handle is one-shot. Preserve the phase for diagnostics, but do not keep
    // the barrier open for a continuation this lifecycle does not own.
    state
        .member_kickoff_pending
        .iter()
        .chain(state.member_kickoff_starting.iter())
        .map(|id| id.0.clone())
        .collect()
}

#[derive(Debug, Clone)]
enum SubmitWorkIngressAuthority {
    Runtime {
        agent_runtime_id: mob_dsl::AgentRuntimeId,
        fence_token: mob_dsl::FenceToken,
        generation: Option<mob_dsl::Generation>,
        session_id: mob_dsl::SessionId,
        work_id: mob_dsl::WorkId,
        origin: mob_dsl::WorkOrigin,
    },
    PeerRuntime {
        agent_runtime_id: mob_dsl::AgentRuntimeId,
        fence_token: mob_dsl::FenceToken,
        generation: Option<mob_dsl::Generation>,
        work_id: mob_dsl::WorkId,
        origin: mob_dsl::WorkOrigin,
    },
}

impl SubmitWorkIngressAuthority {
    fn from_transition(
        transition: &mob_dsl::MobMachineTransition,
        expected_runtime_id: &mob_dsl::AgentRuntimeId,
        expected_fence_token: mob_dsl::FenceToken,
        expected_generation: mob_dsl::Generation,
        expected_work_id: &mob_dsl::WorkId,
        expected_origin: mob_dsl::WorkOrigin,
    ) -> Result<Self, MobError> {
        let mut resolved = None;
        for effect in transition.effects() {
            let authority = match effect {
                mob_dsl::MobMachineEffect::RequestRuntimeIngress {
                    agent_runtime_id,
                    fence_token,
                    generation,
                    session_id,
                    work_id,
                    origin,
                } => Self::Runtime {
                    agent_runtime_id: agent_runtime_id.clone(),
                    fence_token: *fence_token,
                    generation: *generation,
                    session_id: session_id.clone(),
                    work_id: work_id.clone(),
                    origin: *origin,
                },
                mob_dsl::MobMachineEffect::RequestPeerRuntimeIngress {
                    agent_runtime_id,
                    fence_token,
                    generation,
                    work_id,
                    origin,
                } => Self::PeerRuntime {
                    agent_runtime_id: agent_runtime_id.clone(),
                    fence_token: *fence_token,
                    generation: *generation,
                    work_id: work_id.clone(),
                    origin: *origin,
                },
                _ => continue,
            };
            authority.verify_payload(
                expected_runtime_id,
                expected_fence_token,
                expected_generation,
                expected_work_id,
                expected_origin,
            )?;
            if resolved.replace(authority).is_some() {
                return Err(MobError::Internal(
                    "MobMachine SubmitWork emitted multiple generated runtime ingress authorities"
                        .to_string(),
                ));
            }
        }
        resolved.ok_or_else(|| {
            MobError::Internal(
                "MobMachine accepted SubmitWork but emitted no generated runtime ingress authority"
                    .to_string(),
            )
        })
    }

    fn variant(&self) -> &'static str {
        match self {
            Self::Runtime { .. } => "RequestRuntimeIngress",
            Self::PeerRuntime { .. } => "RequestPeerRuntimeIngress",
        }
    }

    fn agent_runtime_id(&self) -> &mob_dsl::AgentRuntimeId {
        match self {
            Self::Runtime {
                agent_runtime_id, ..
            }
            | Self::PeerRuntime {
                agent_runtime_id, ..
            } => agent_runtime_id,
        }
    }

    fn fence_token(&self) -> mob_dsl::FenceToken {
        match self {
            Self::Runtime { fence_token, .. } | Self::PeerRuntime { fence_token, .. } => {
                *fence_token
            }
        }
    }

    fn generation(&self) -> Option<mob_dsl::Generation> {
        match self {
            Self::Runtime { generation, .. } | Self::PeerRuntime { generation, .. } => *generation,
        }
    }

    fn work_id(&self) -> &mob_dsl::WorkId {
        match self {
            Self::Runtime { work_id, .. } | Self::PeerRuntime { work_id, .. } => work_id,
        }
    }

    fn origin(&self) -> mob_dsl::WorkOrigin {
        match self {
            Self::Runtime { origin, .. } | Self::PeerRuntime { origin, .. } => *origin,
        }
    }

    fn verify_payload(
        &self,
        expected_runtime_id: &mob_dsl::AgentRuntimeId,
        expected_fence_token: mob_dsl::FenceToken,
        expected_generation: mob_dsl::Generation,
        expected_work_id: &mob_dsl::WorkId,
        expected_origin: mob_dsl::WorkOrigin,
    ) -> Result<(), MobError> {
        if self.agent_runtime_id() != expected_runtime_id
            || self.fence_token() != expected_fence_token
            || self.generation() != Some(expected_generation)
            || self.work_id() != expected_work_id
            || self.origin() != expected_origin
        {
            return Err(MobError::Internal(format!(
                "generated {} authority did not match admitted SubmitWork payload",
                self.variant()
            )));
        }
        Ok(())
    }

    fn verify_member_ref(&self, member_ref: &MemberRef, context: &str) -> Result<(), MobError> {
        match self {
            Self::Runtime { session_id, .. } => {
                let Some(bridge_session_id) = member_ref.bridge_session_id() else {
                    return Err(MobError::Internal(format!(
                        "{context} requires a session-bound member for generated {} authority",
                        self.variant()
                    )));
                };
                let projected_session_id = mob_dsl::SessionId::from_domain(bridge_session_id);
                if &projected_session_id != session_id {
                    return Err(MobError::Internal(format!(
                        "{context} generated {} authority session does not match MobMachine session binding",
                        self.variant()
                    )));
                }
                Ok(())
            }
            Self::PeerRuntime { .. } => match member_ref {
                MemberRef::BackendPeer {
                    session_id: None, ..
                } => Ok(()),
                _ => Err(MobError::Internal(format!(
                    "{context} requires a peer-only member for generated {} authority",
                    self.variant()
                ))),
            },
        }
    }

    fn is_peer_runtime(&self) -> bool {
        matches!(self, Self::PeerRuntime { .. })
    }
}

// Sized for real mob-scale startup/shutdown fan-out (50+ members).
#[cfg(not(target_arch = "wasm32"))]
const MAX_PARALLEL_REMOTE_MEMBER_TEARDOWNS: usize = 64;
const MAX_LIFECYCLE_NOTIFICATION_TASKS: usize = 16;
const MAX_PARALLEL_PEER_RETIRE_NOTIFICATIONS: usize = 64;
const MAX_CONCURRENT_AUTONOMOUS_STOP_INTERRUPTS: usize = 8;
#[cfg(not(test))]
pub(super) const MAX_PENDING_PEER_DELIVERIES: usize = 1024;
#[cfg(test)]
pub(super) const MAX_PENDING_PEER_DELIVERIES: usize = 4;

pub(super) fn advance_rotating_cursor(
    item_count: usize,
    rotation: usize,
    last_selected_offset: Option<usize>,
) -> usize {
    if item_count == 0 {
        return 0;
    }
    match last_selected_offset {
        Some(offset) => (rotation + offset + 1) % item_count,
        None => (rotation + 1) % item_count,
    }
}

pub(super) fn lifecycle_origin_fenced(state: &mob_dsl::MobMachineState) -> bool {
    state.placed_completion_lifecycle_quiescing
        || state.placed_completion_lifecycle_intent.is_some()
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum AutonomousStopPhase {
    WaitForPlacedKickoffCleanup,
    DriveInterrupts,
}

fn autonomous_stop_phase(pending_kickoffs: usize, resolved_kickoffs: usize) -> AutonomousStopPhase {
    if pending_kickoffs != 0 || resolved_kickoffs != 0 {
        AutonomousStopPhase::WaitForPlacedKickoffCleanup
    } else {
        AutonomousStopPhase::DriveInterrupts
    }
}

