/// Render a mob member's comms (peer) routing name from typed components
/// through the single owner [`meerkat_core::MemberCommsName`].
///
/// The components here are already typed mob slugs (`MobId`/`ProfileName`/
/// `AgentIdentity`), so construction normally succeeds; the join is owned by
/// `MemberCommsName::Display` rather than an inline `format!`. A component that
/// fails the slug rule fails closed as a typed [`MobError::MemberCommsName`]
/// rather than reconstructing the raw `mob_id/role/member` join that the single
/// owner already rejected.
pub(super) fn render_member_comms_name(
    mob_id: &str,
    role: &str,
    member: &str,
) -> Result<String, MobError> {
    Ok(meerkat_core::MemberCommsName::new(mob_id, role, member)?.to_string())
}

fn observed_runtime_id(signal: &mob_dsl::MobMachineSignal) -> Option<&mob_dsl::AgentRuntimeId> {
    match signal {
        mob_dsl::MobMachineSignal::ObserveRuntimeReady {
            agent_runtime_id, ..
        }
        | mob_dsl::MobMachineSignal::ObserveRuntimeRetired {
            agent_runtime_id, ..
        }
        | mob_dsl::MobMachineSignal::ObserveRuntimeDestroyed {
            agent_runtime_id, ..
        } => Some(agent_runtime_id),
        _ => None,
    }
}

fn foreign_runtime_observation<'a>(
    state: &mob_dsl::MobMachineState,
    signal: &'a mob_dsl::MobMachineSignal,
) -> Option<&'a mob_dsl::AgentRuntimeId> {
    let agent_runtime_id = observed_runtime_id(signal)?;
    (!state.live_runtime_ids.contains(agent_runtime_id)).then_some(agent_runtime_id)
}

/// Bridge budget for one `InstallPeerTrust`/`RemovePeerTrust` route-install
/// send (ADJ-3/ADJ-4 precedent: same 60s materialize budget, exactly one
/// resend of the same payload on TIMEOUT only — a delivered rejection
/// leaves the obligation for the event-driven retry lanes).
const ROUTE_INSTALL_BRIDGE_TIMEOUT: std::time::Duration = std::time::Duration::from_secs(60);
pub(super) const EXACT_EVENT_RECONCILE_PAGE_SIZE: usize = 64;
const EXACT_EVENT_RECONCILE_READ_ATTEMPTS: usize = 2;

/// Reconcile an append error that may have happened after the write. The
/// cursor floor distinguishes this operation from an identical structural
/// event in an earlier wire/unwire cycle.
pub(super) async fn reconcile_exact_mob_event_after_cursor(
    events: &(dyn MobEventStore + 'static),
    mob_id: &MobId,
    cursor_floor: u64,
    desired: &MobEventKind,
) -> Result<Option<MobEvent>, MobError> {
    // Freeze the scan horizon after the append returned. This both bounds the
    // reconciliation under concurrent writers and avoids mistaking a later
    // identical operation for the one whose acknowledgement was lost.
    let scan_ceiling = {
        let mut last_error = None;
        let mut ceiling = None;
        for attempt in 1..=EXACT_EVENT_RECONCILE_READ_ATTEMPTS {
            match events.latest_cursor().await {
                Ok(cursor) => {
                    ceiling = Some(cursor);
                    break;
                }
                Err(error) => {
                    last_error = Some(error);
                    if attempt < EXACT_EVENT_RECONCILE_READ_ATTEMPTS {
                        tracing::warn!(
                            mob_id = %mob_id,
                            attempt,
                            "exact event reconciliation latest-cursor read failed transiently; retrying"
                        );
                        tokio::task::yield_now().await;
                    }
                }
            }
        }
        match ceiling {
            Some(cursor) => cursor,
            None => {
                return Err(MobError::Internal(format!(
                    "exact event reconciliation could not freeze a cursor ceiling after {EXACT_EVENT_RECONCILE_READ_ATTEMPTS} attempts: {}",
                    last_error
                        .map(|error| error.to_string())
                        .unwrap_or_else(|| "unknown store error".to_string())
                )));
            }
        }
    };
    if scan_ceiling <= cursor_floor {
        return Ok(None);
    }

    let mut after_cursor = cursor_floor;
    while after_cursor < scan_ceiling {
        // Retry the SAME page after one transient read failure. The frozen
        // ceiling above is never recaptured: an event appended while this
        // retry is in flight cannot authorize the earlier uncertain append.
        let page = {
            let mut last_error = None;
            let mut page = None;
            for attempt in 1..=EXACT_EVENT_RECONCILE_READ_ATTEMPTS {
                match events
                    .poll(after_cursor, EXACT_EVENT_RECONCILE_PAGE_SIZE)
                    .await
                {
                    Ok(events) => {
                        page = Some(events);
                        break;
                    }
                    Err(error) => {
                        last_error = Some(error);
                        if attempt < EXACT_EVENT_RECONCILE_READ_ATTEMPTS {
                            tracing::warn!(
                                mob_id = %mob_id,
                                after_cursor,
                                scan_ceiling,
                                attempt,
                                "exact event reconciliation page read failed transiently; retrying the same page"
                            );
                            tokio::task::yield_now().await;
                        }
                    }
                }
            }
            match page {
                Some(events) => events,
                None => {
                    return Err(MobError::Internal(format!(
                        "exact event reconciliation could not read the page after cursor {after_cursor} below ceiling {scan_ceiling} after {EXACT_EVENT_RECONCILE_READ_ATTEMPTS} attempts: {}",
                        last_error
                            .map(|error| error.to_string())
                            .unwrap_or_else(|| "unknown store error".to_string())
                    )));
                }
            }
        };
        if page.is_empty() {
            return Err(MobError::Internal(format!(
                "exact event reconciliation made no progress below cursor ceiling {scan_ceiling} (stuck after {after_cursor})"
            )));
        }
        let page_start = after_cursor;
        for event in page {
            if event.cursor <= after_cursor {
                return Err(MobError::Internal(format!(
                    "exact event reconciliation received non-increasing cursor {} after {}",
                    event.cursor, after_cursor
                )));
            }
            if event.cursor > scan_ceiling {
                break;
            }
            after_cursor = event.cursor;
            if event.mob_id == *mob_id && event.kind == *desired {
                return Ok(Some(event));
            }
        }
        if after_cursor <= page_start {
            return Err(MobError::Internal(format!(
                "exact event reconciliation page did not advance beyond cursor {page_start}"
            )));
        }
    }
    Ok(None)
}

/// Host revoke may synchronously quiesce and archive every materialized
/// member on the target daemon. It is deliberately wider than an ordinary
/// bridge command while remaining bounded for retry convergence.
const HOST_REVOKE_BRIDGE_TIMEOUT: std::time::Duration = std::time::Duration::from_secs(120);

#[derive(Clone)]
enum WiringEndpoint {
    Local {
        entry: Box<RosterEntry>,
        comms: Arc<dyn CoreCommsRuntime>,
        spec: TrustedPeerDescriptor,
        comms_name: String,
    },
    PeerOnly {
        spec: TrustedPeerDescriptor,
        binding: crate::RuntimeBinding,
    },
    /// Member placed on a bound remote host (multi-host §10.4). Peer
    /// material is MACHINE-owned: `member_peer_endpoints[identity]`, the
    /// ack-recorded pubkey @ host acceptor address. Trust for the remote
    /// side rides a `RouteInstallObligation`, never a direct runtime write.
    Placed {
        identity: AgentIdentity,
        host: mob_dsl::HostId,
        spec: TrustedPeerDescriptor,
    },
}

impl WiringEndpoint {
    fn spec(&self) -> &TrustedPeerDescriptor {
        match self {
            Self::Local { spec, .. } | Self::PeerOnly { spec, .. } | Self::Placed { spec, .. } => {
                spec
            }
        }
    }
}

#[derive(Clone)]
struct LocalBatchWiringEndpoint {
    comms: Arc<dyn CoreCommsRuntime>,
    spec: TrustedPeerDescriptor,
    removal_key: String,
}

/// Batch wiring endpoint classification (multi-host §10.4): local
/// session-backed members keep today's in-process trust lane; placed
/// members carry their machine peer material and their installs ride the
/// route-install obligation lane.
#[derive(Clone)]
enum BatchWiringEndpoint {
    Local(LocalBatchWiringEndpoint),
    Placed {
        spec: TrustedPeerDescriptor,
        removal_key: String,
    },
}

impl BatchWiringEndpoint {
    fn spec(&self) -> &TrustedPeerDescriptor {
        match self {
            Self::Local(local) => &local.spec,
            Self::Placed { spec, .. } => spec,
        }
    }

    fn removal_key(&self) -> &str {
        match self {
            Self::Local(local) => &local.removal_key,
            Self::Placed { removal_key, .. } => removal_key,
        }
    }
}

/// Per-mob registration view into the process-scoped controlling acceptor.
/// The shared config owns the single D1 listener; this state remembers only
/// identities registered by this actor so unwire/shutdown cannot remove a
/// different mob's rows.
#[cfg(not(target_arch = "wasm32"))]
pub(super) struct ControllingAcceptorState {
    config: super::builder::ControllingAcceptorConfig,
    registered: BTreeMap<String, super::builder::ControllingAcceptorRegistrationLease>,
}

#[cfg(not(target_arch = "wasm32"))]
impl ControllingAcceptorState {
    pub(super) fn new(config: super::builder::ControllingAcceptorConfig) -> Self {
        Self {
            config,
            registered: BTreeMap::new(),
        }
    }

    /// Publish current session material and retain the exact lease owned by
    /// this actor. This deliberately does not treat durable pubkey presence as
    /// idempotency: session revival preserves the key while replacing inbox.
    pub(super) async fn refresh_registration(
        &mut self,
        logical_owner: String,
        registration: super::builder::MemberAcceptorRegistration,
    ) -> Result<String, MobError> {
        let pubkey_string = registration.pubkey.to_pubkey_string();
        let lease = self.config.register(logical_owner, registration).await?;
        let advertised = lease.advertised_address.clone();
        self.registered.insert(pubkey_string, lease);
        Ok(advertised)
    }

    /// Remove this actor's exact registration lease for `pubkey`. If the
    /// process registry has already advanced to a replacement lease, the
    /// shared compare-remove is a no-op. Retain the actor lease when removal
    /// itself fails so lifecycle retry can redrive the same cleanup.
    pub(super) async fn remove_registration(
        &mut self,
        pubkey: &meerkat_comms::PubKey,
    ) -> Result<(), MobError> {
        let pubkey_string = pubkey.to_pubkey_string();
        let Some(lease) = self.registered.remove(&pubkey_string) else {
            return Ok(());
        };
        if let Err(error) = self.config.remove(&lease).await {
            self.registered.insert(pubkey_string, lease);
            return Err(error);
        }
        Ok(())
    }

    #[cfg(test)]
    pub(super) fn registration_token(&self, pubkey: &str) -> Option<Arc<()>> {
        self.registered
            .get(pubkey)
            .map(|lease| Arc::clone(&lease.token))
    }

    /// Remove this actor's projections. The process-level listener remains
    /// live for sibling mobs that share the same config.
    pub(super) async fn shutdown(self) {
        for lease in self.registered.into_values() {
            if let Err(error) = self.config.remove(&lease).await {
                tracing::warn!(%error, "failed to remove controlling acceptor row at mob shutdown");
            }
        }
    }
}

