pub(super) fn placed_kickoff_snapshot_for_structural_event(
    state: &mob_dsl::MobMachineState,
    agent_identity: &AgentIdentity,
    timestamp_hint: Option<&crate::roster::MobMemberKickoffSnapshot>,
    now: SystemTime,
) -> Result<crate::roster::MobMemberKickoffSnapshot, MobError> {
    let mut kickoff = kickoff_snapshot_from_machine_state(
        agent_identity.as_str(),
        state,
        timestamp_hint,
    )
    .ok_or_else(|| {
        MobError::Internal(format!(
            "prepared placed-kickoff transition produced no kickoff projection for '{agent_identity}'"
        ))
    })?;
    // Structural carriers include the public kickoff projection. Exact
    // machine replays must therefore reuse its existing timestamp or the
    // otherwise-identical retry would append a second Record/terminal pair
    // that cold recovery correctly rejects as conflicting custody. A real
    // lifecycle change mints a fresh presentation timestamp.
    if timestamp_hint.as_ref().is_none_or(|existing| {
        existing.objective_id != kickoff.objective_id
            || existing.phase != kickoff.phase
            || existing.error != kickoff.error
    }) {
        kickoff.updated_at = now;
    }
    Ok(kickoff)
}

enum PlacedKickoffStructuralReplay<'a> {
    Record {
        obligation: &'a crate::event::PlacedKickoffObligationEvent,
    },
    Resolved {
        obligation: &'a crate::event::PlacedKickoffObligationEvent,
        outcome: &'a crate::event::PlacedKickoffHostOutcomeEvent,
    },
    RejectedNoEffect {
        obligation: &'a crate::event::PlacedKickoffObligationEvent,
        error: &'a str,
    },
}

impl PlacedKickoffStructuralReplay<'_> {
    fn obligation(&self) -> &crate::event::PlacedKickoffObligationEvent {
        match self {
            Self::Record { obligation }
            | Self::Resolved { obligation, .. }
            | Self::RejectedNoEffect { obligation, .. } => obligation,
        }
    }

    fn input_id(&self) -> &str {
        match self {
            Self::Record { obligation }
            | Self::Resolved { obligation, .. }
            | Self::RejectedNoEffect { obligation, .. } => &obligation.input_id,
        }
    }

    fn carrier_name(&self) -> &'static str {
        match self {
            Self::Record { .. } => "PlacedKickoffObligationRecorded",
            Self::Resolved { .. } => "PlacedKickoffOutcomeResolved",
            Self::RejectedNoEffect { .. } => "PlacedKickoffRejectedNoEffect",
        }
    }
}

fn existing_placed_kickoff_structural_carrier(
    events: &[MobEvent],
    mob_id: &MobId,
    expected: PlacedKickoffStructuralReplay<'_>,
) -> Result<Option<crate::roster::MobMemberKickoffSnapshot>, MobError> {
    let mob_events = events
        .iter()
        .filter(|event| &event.mob_id == mob_id)
        .collect::<Vec<_>>();
    let epoch_start = mob_events
        .iter()
        .rposition(|event| matches!(event.kind, MobEventKind::MobReset))
        .map_or(0, |index| index + 1);
    let epoch = &mob_events[epoch_start..];
    let expected_turn_key = PlacedTrackedInputKey::kickoff(expected.obligation());
    let mut exact_match = None;
    for (index, event) in epoch.iter().enumerate() {
        let (obligation, embedded_kickoff, exact) = match (&expected, &event.kind) {
            (
                PlacedKickoffStructuralReplay::Record {
                    obligation: expected,
                },
                MobEventKind::PlacedKickoffObligationRecorded { obligation },
            ) if PlacedTrackedInputKey::kickoff(obligation) == expected_turn_key => {
                (obligation, None, obligation == *expected)
            }
            (
                PlacedKickoffStructuralReplay::Resolved {
                    obligation: expected,
                    outcome: expected_outcome,
                },
                MobEventKind::PlacedKickoffOutcomeResolved {
                    obligation,
                    outcome,
                    kickoff,
                },
            ) if PlacedTrackedInputKey::kickoff(obligation) == expected_turn_key => (
                obligation,
                Some(kickoff),
                obligation == *expected && outcome == *expected_outcome,
            ),
            (
                PlacedKickoffStructuralReplay::RejectedNoEffect {
                    obligation: expected,
                    error: expected_error,
                },
                MobEventKind::PlacedKickoffRejectedNoEffect {
                    obligation,
                    error,
                    kickoff,
                },
            ) if PlacedTrackedInputKey::kickoff(obligation) == expected_turn_key => (
                obligation,
                Some(kickoff),
                obligation == *expected && error == *expected_error,
            ),
            _ => continue,
        };
        if !exact {
            return Err(MobError::Internal(format!(
                "{} replay for input '{}' conflicts with its durable carrier",
                expected.carrier_name(),
                expected.input_id()
            )));
        }
        let paired = epoch.get(index + 1).ok_or_else(|| {
            MobError::Internal(format!(
                "{} replay for input '{}' has no paired kickoff projection",
                expected.carrier_name(),
                expected.input_id()
            ))
        })?;
        let MobEventKind::MemberKickoffUpdated { member, kickoff } = &paired.kind else {
            return Err(MobError::Internal(format!(
                "{} replay for input '{}' is not immediately followed by its kickoff projection",
                expected.carrier_name(),
                expected.input_id()
            )));
        };
        let pair_exact = member == &obligation.agent_identity
            && match embedded_kickoff {
                Some(embedded) => kickoff == embedded,
                None => {
                    kickoff.objective_id == Some(obligation.objective_id)
                        && kickoff.phase == crate::roster::MobMemberKickoffPhase::Starting
                        && kickoff.error.is_none()
                }
            };
        if !pair_exact {
            return Err(MobError::Internal(format!(
                "{} replay for input '{}' has a mismatched kickoff projection",
                expected.carrier_name(),
                expected.input_id()
            )));
        }
        if exact_match.replace(kickoff.clone()).is_some() {
            return Err(MobError::Internal(format!(
                "{} replay for input '{}' found duplicate exact durable carriers",
                expected.carrier_name(),
                expected.input_id()
            )));
        }
    }
    Ok(exact_match)
}

fn exact_structural_batch_present(
    events: &[MobEvent],
    mob_id: &MobId,
    desired: &[MobEventKind],
) -> Result<bool, MobError> {
    let Some(structural_head) = desired.first() else {
        return Ok(true);
    };
    let mob_events = events
        .iter()
        .filter(|event| &event.mob_id == mob_id)
        .collect::<Vec<_>>();
    let epoch_start = mob_events
        .iter()
        .rposition(|event| matches!(event.kind, MobEventKind::MobReset))
        .map_or(0, |index| index + 1);
    let epoch = &mob_events[epoch_start..];
    if epoch
        .windows(desired.len())
        .any(|window| window.iter().map(|event| &event.kind).eq(desired.iter()))
    {
        return Ok(true);
    }

    // The first event is the correlation-scoped structural carrier. Its
    // presence without the exact following batch proves a partial or
    // conflicting write. Trailing projection events are deliberately not
    // unique: cancellation can first persist `MemberKickoffUpdated(Cancelled)`
    // and later pair that same projection with the authenticated host outcome.
    if epoch.iter().any(|event| &event.kind == structural_head) {
        return Err(MobError::Internal(
            "durable structural batch is partial or out of order in the current mob epoch"
                .to_string(),
        ));
    }
    Ok(false)
}

