#[derive(Debug, Clone)]
enum WireTrustAuthority {
    GraphAdded(MemberTrustHandoff),
    RepairRequested(MemberTrustHandoff),
    ExternalGraphAdded(CommsTrustMutationAuthority),
    ExternalRepairRequested(CommsTrustMutationAuthority),
}

impl WireTrustAuthority {
    fn dsl_added(&self) -> bool {
        matches!(self, Self::GraphAdded(_) | Self::ExternalGraphAdded(_))
    }

    fn is_repair(&self) -> bool {
        matches!(
            self,
            Self::RepairRequested(_) | Self::ExternalRepairRequested(_)
        )
    }

    fn member_handoff(&self) -> Result<&MemberTrustHandoff, MobError> {
        match self {
            Self::GraphAdded(handoff) | Self::RepairRequested(handoff) => Ok(handoff),
            Self::ExternalGraphAdded(_) | Self::ExternalRepairRequested(_) => {
                Err(MobError::WiringError(
                    "external peer authority does not carry member peer handoff".to_string(),
                ))
            }
        }
    }

    fn external_authority(&self) -> Result<&CommsTrustMutationAuthority, MobError> {
        match self {
            Self::ExternalGraphAdded(authority) | Self::ExternalRepairRequested(authority) => {
                Ok(authority)
            }
            Self::GraphAdded(_) | Self::RepairRequested(_) => Err(MobError::WiringError(
                "member trust authority does not carry external peer authority".to_string(),
            )),
        }
    }
}

#[derive(Debug, Clone)]
struct MemberTrustHandoff {
    edge: mob_dsl::WiringEdge,
    authority: MemberTrustAuthority,
    operation: MemberTrustOperation,
}

#[derive(Debug, Clone)]
enum MemberTrustAuthority {
    Wiring(crate::generated::protocol_mob_member_trust_wiring::MobMemberTrustWiringObligation),
    Unwiring(
        crate::generated::protocol_mob_member_trust_unwiring::MobMemberTrustUnwiringObligation,
    ),
    Repair(crate::generated::protocol_mob_member_trust_wiring::MobMemberTrustWiringObligation),
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum MemberTrustOperation {
    Wiring,
    Unwiring,
    Repair,
}

impl MemberTrustHandoff {
    fn peer_id_for(&self, identity: &AgentIdentity) -> Result<&str, MobError> {
        let identity = mob_dsl::AgentIdentity::from_domain(identity);
        let actual = match &self.authority {
            MemberTrustAuthority::Wiring(obligation) | MemberTrustAuthority::Repair(obligation) => {
                if obligation.edge().a == identity {
                    Some(obligation.a_peer_id().0.as_str())
                } else if obligation.edge().b == identity {
                    Some(obligation.b_peer_id().0.as_str())
                } else {
                    None
                }
            }
            MemberTrustAuthority::Unwiring(obligation) => {
                if obligation.edge().a == identity {
                    Some(obligation.a_peer_id().0.as_str())
                } else if obligation.edge().b == identity {
                    Some(obligation.b_peer_id().0.as_str())
                } else {
                    None
                }
            }
        };
        actual.ok_or_else(|| {
            MobError::WiringError(format!(
                "generated member trust obligation does not cover '{identity:?}'"
            ))
        })
    }

    fn require_peer_id_for(
        &self,
        identity: &AgentIdentity,
        expected_peer_id: &str,
    ) -> Result<(), MobError> {
        let actual = self.peer_id_for(identity)?;
        if actual == expected_peer_id {
            Ok(())
        } else {
            Err(MobError::WiringError(format!(
                "generated member trust handoff peer id '{actual}' does not match resolved peer id '{expected_peer_id}' for '{identity}'"
            )))
        }
    }

    fn wiring_authority_for(
        &self,
        identity: &AgentIdentity,
        expected_peer_id: &str,
        live_authority: &mob_dsl::MobMachineAuthority,
    ) -> Result<CommsTrustMutationAuthority, MobError> {
        match &self.authority {
            MemberTrustAuthority::Wiring(obligation) => {
                crate::generated::protocol_mob_member_trust_wiring::wiring_authority_for_identity_with_live_authority(
                    obligation,
                    identity.as_str(),
                    expected_peer_id,
                    live_authority,
                )
                .map_err(MobError::WiringError)
            }
            MemberTrustAuthority::Repair(_) | MemberTrustAuthority::Unwiring(_) => {
                Err(MobError::WiringError(
                    "generated member trust obligation cannot wire trust".to_string(),
                ))
            }
        }
    }

    fn unwiring_authority_for(
        &self,
        identity: &AgentIdentity,
        expected_peer_id: &str,
    ) -> Result<CommsTrustMutationAuthority, MobError> {
        match &self.authority {
            MemberTrustAuthority::Unwiring(obligation) => {
                crate::generated::protocol_mob_member_trust_unwiring::unwiring_authority_for_identity(
                    obligation,
                    identity.as_str(),
                    expected_peer_id,
                )
                .map_err(MobError::WiringError)
            }
            MemberTrustAuthority::Wiring(_) | MemberTrustAuthority::Repair(_) => {
                Err(MobError::WiringError(
                    "generated member trust obligation cannot unwire trust".to_string(),
                ))
            }
        }
    }

    fn repair_authority_for(
        &self,
        identity: &AgentIdentity,
        expected_peer_id: &str,
        live_authority: &mob_dsl::MobMachineAuthority,
    ) -> Result<CommsTrustMutationAuthority, MobError> {
        match &self.authority {
            MemberTrustAuthority::Repair(obligation) => {
                crate::generated::protocol_mob_member_trust_wiring::repair_authority_for_identity_with_live_authority(
                    obligation,
                    identity.as_str(),
                    expected_peer_id,
                    live_authority,
                )
                .map_err(MobError::WiringError)
            }
            MemberTrustAuthority::Wiring(_) | MemberTrustAuthority::Unwiring(_) => {
                Err(MobError::WiringError(
                    "generated member trust obligation cannot repair trust".to_string(),
                ))
            }
        }
    }

    fn add_authority_for(
        &self,
        identity: &AgentIdentity,
        expected_peer_id: &str,
        live_authority: &mob_dsl::MobMachineAuthority,
    ) -> Result<CommsTrustMutationAuthority, MobError> {
        match self.operation {
            MemberTrustOperation::Wiring => {
                self.wiring_authority_for(identity, expected_peer_id, live_authority)
            }
            MemberTrustOperation::Repair => {
                self.repair_authority_for(identity, expected_peer_id, live_authority)
            }
            MemberTrustOperation::Unwiring => Err(MobError::WiringError(
                "generated member unwiring handoff cannot add trust".to_string(),
            )),
        }
    }
}

/// Resolve the runtime binding for a spawn request.
///
/// `RuntimeBinding` takes precedence over the legacy `backend` tag. When neither
/// is provided, resolves from profile/definition defaults. `External` without
/// a concrete `RuntimeBinding` is an error — you cannot spawn an external
/// member without declaring the real process identity.
fn resolve_binding(
    binding: Option<crate::RuntimeBinding>,
    backend: Option<crate::MobBackendKind>,
    profile_backend: Option<crate::MobBackendKind>,
    definition_default: crate::MobBackendKind,
    agent_identity: &AgentIdentity,
) -> Result<crate::RuntimeBinding, MobError> {
    if let Some(b) = binding {
        return Ok(b);
    }
    let kind = backend.or(profile_backend).unwrap_or(definition_default);
    match kind {
        crate::MobBackendKind::Session => Ok(crate::RuntimeBinding::Session),
        crate::MobBackendKind::External => Err(MobError::WiringError(format!(
            "external backend requires explicit RuntimeBinding for '{agent_identity}'"
        ))),
    }
}

fn normalize_runtime_mode_for_binding(
    runtime_mode: crate::MobRuntimeMode,
    binding: &crate::RuntimeBinding,
) -> crate::MobRuntimeMode {
    match binding {
        crate::RuntimeBinding::External { .. } => crate::MobRuntimeMode::TurnDriven,
        // Placed members support BOTH modes (plan §7.3): the forced-
        // TurnDriven normalization stays External-only.
        crate::RuntimeBinding::Session | crate::RuntimeBinding::HostMaterialized { .. } => {
            runtime_mode
        }
    }
}

fn with_spawn_budget_limits(
    mut req: meerkat_core::service::CreateSessionRequest,
    limits: Option<meerkat_core::BudgetLimits>,
) -> meerkat_core::service::CreateSessionRequest {
    if let Some(limits) = limits {
        req.build
            .get_or_insert_with(meerkat_core::service::SessionBuildOptions::default)
            .budget_limits = Some(limits);
    }
    req
}

pub(super) fn admit_bridge_session_for_spawn(
    req: &mut meerkat_core::service::CreateSessionRequest,
) -> SessionId {
    let build = req
        .build
        .get_or_insert_with(meerkat_core::service::SessionBuildOptions::default);
    if let Some(session) = build.resume_session.as_ref() {
        return session.id().clone();
    }
    let session_id = SessionId::new();
    build.resume_session = Some(meerkat_core::session::Session::with_id(session_id.clone()));
    session_id
}

/// Project a DSL `MobPhase` into the shell `MobState` enum. Used by
/// `MobActor::state()` and by the `MobCommand::QueryPhase` reply so that
/// external `MobHandle::status()` callers observe the same DSL-authority
/// value the actor uses internally (dogma #1, #13, #17).
fn project_dsl_phase(phase: mob_dsl::MobPhase) -> MobState {
    match phase {
        mob_dsl::MobPhase::Running => MobState::Running,
        mob_dsl::MobPhase::Stopped => MobState::Stopped,
        mob_dsl::MobPhase::Completed => MobState::Completed,
        mob_dsl::MobPhase::Destroyed => MobState::Destroyed,
    }
}

/// Row #314: derive the machine-owned external-member rebind capability from a
/// member's `MemberRef` bootstrap proof. A backend peer with a non-empty
/// bootstrap token can be supervisor-rebound; session-backed members and peers
/// without a usable token cannot.
pub(super) fn external_member_rebind_capability_from_member_ref(
    member_ref: &MemberRef,
) -> mob_dsl::ExternalMemberRebindCapability {
    match member_ref {
        MemberRef::BackendPeer {
            bootstrap_token, ..
        } if bootstrap_token
            .as_ref()
            .is_some_and(|token| !token.is_empty()) =>
        {
            mob_dsl::ExternalMemberRebindCapability::Available
        }
        _ => mob_dsl::ExternalMemberRebindCapability::Unavailable,
    }
}

/// Extract the pure wire runtime-state observation for MobMachine terminality
/// classification. This is a faithful 1:1 projection of the observed
/// `BridgeMemberRuntimeState`; the terminal/non-terminal verdict is decided by
/// MobMachine, not here. `BridgeMemberRuntimeState` is `#[non_exhaustive]`, so
/// an unrecognized wire state fails closed rather than being silently coerced
/// to a (non-terminal) default.
fn remote_member_runtime_observed_state(
    state: super::bridge_protocol::BridgeMemberRuntimeState,
) -> Result<mob_dsl::MobRemoteMemberRuntimeObservedState, MobError> {
    use super::bridge_protocol::BridgeMemberRuntimeState as Wire;
    use mob_dsl::MobRemoteMemberRuntimeObservedState as Observed;
    Ok(match state {
        Wire::Initializing => Observed::Initializing,
        Wire::Idle => Observed::Idle,
        Wire::Attached => Observed::Attached,
        Wire::Running => Observed::Running,
        Wire::Retired => Observed::Retired,
        Wire::Stopped => Observed::Stopped,
        Wire::Destroyed => Observed::Destroyed,
        other => {
            return Err(MobError::Internal(format!(
                "unrecognized remote-member runtime wire state `{other}` cannot be classified for terminality"
            )));
        }
    })
}

/// Map a typed wire bridge rejection cause onto the MobMachine observation
/// enum. The wire cause is `#[non_exhaustive]`; any future variant the mob does
/// not yet understand maps to `Internal`, which MobMachine classifies as
/// `FatalBubbleUp` — failing closed (no recovery) on an unrecognized cause.
fn mob_bridge_rejection_cause(
    cause: super::bridge_protocol::BridgeRejectionCause,
) -> mob_dsl::MobBridgeRejectionCause {
    use super::bridge_protocol::BridgeRejectionCause as Wire;
    use mob_dsl::MobBridgeRejectionCause as Mob;
    match cause {
        Wire::NotBound => Mob::NotBound,
        Wire::StaleSupervisor => Mob::StaleSupervisor,
        Wire::SenderMismatch => Mob::SenderMismatch,
        Wire::AlreadyBound => Mob::AlreadyBound,
        Wire::InvalidBootstrapToken => Mob::InvalidBootstrapToken,
        Wire::UnsupportedProtocolVersion => Mob::UnsupportedProtocolVersion,
        Wire::InvalidSupervisorSpec => Mob::InvalidSupervisorSpec,
        Wire::InvalidPeerSpec => Mob::InvalidPeerSpec,
        Wire::AddressMismatch => Mob::AddressMismatch,
        Wire::Unsupported => Mob::Unsupported,
        Wire::Internal => Mob::Internal,
        // Fail closed: an unknown future wire cause is treated as a hard
        // (fatal) rejection that no rebind can recover.
        _ => Mob::Internal,
    }
}

/// Render forked conversation rows as a text context block for the new
/// member. ONE renderer over the ONE page row vocabulary
/// (`WireSessionMessage`, DEC-P6E-20): the local fork branch projects its
/// domain page through `WireMemberHistoryPageBody::try_from_history_page` and
/// the remote branch decodes the bridge page — both render here, so local
/// and remote fork context are byte-identical by construction.
fn render_fork_context(
    source_member_id: &AgentIdentity,
    rows: &[meerkat_contracts::wire::WireHistoryRow],
) -> String {
    use meerkat_contracts::wire::{
        WireAssistantBlock, WireContentBlock, WireContentInput, WireSessionMessage,
        WireToolResultContent,
    };

    fn content_input_text(content: &WireContentInput) -> String {
        match content {
            WireContentInput::Text(text) => text.clone(),
            WireContentInput::Blocks(blocks) => blocks
                .iter()
                .filter_map(|block| match block {
                    WireContentBlock::Text { text } => Some(text.as_str()),
                    _ => None,
                })
                .collect::<Vec<_>>()
                .join(""),
        }
    }

    let mut lines = Vec::new();
    lines.push(format!(
        "[Forked conversation context from member '{source_member_id}']"
    ));
    for row in rows {
        match &row.0 {
            WireSessionMessage::System { content, .. } => {
                lines.push(format!("[system]: {content}"));
            }
            WireSessionMessage::SystemNotice { body, .. } => {
                lines.push(format!(
                    "[system_notice]: {}",
                    body.clone().unwrap_or_default()
                ));
            }
            WireSessionMessage::User { content, .. } => {
                lines.push(format!("[user]: {}", content_input_text(content)));
            }
            WireSessionMessage::BlockAssistant { blocks, .. } => {
                // Both `Text` (display) and `Transcript` (spoken) lanes
                // project to the rendered text stream; supervisor sees the
                // assistant's full visible output regardless of lane.
                let text: String = blocks
                    .iter()
                    .filter_map(|block| match block {
                        WireAssistantBlock::Text { text, .. }
                        | WireAssistantBlock::Transcript { text, .. } => Some(text.as_str()),
                        _ => None,
                    })
                    .collect::<Vec<_>>()
                    .join("");
                if !text.is_empty() {
                    lines.push(format!("[assistant]: {text}"));
                }
            }
            WireSessionMessage::ToolResults { results, .. } => {
                for result in results {
                    let text: String = match &result.content {
                        WireToolResultContent::Text(text) => text.clone(),
                        WireToolResultContent::Blocks(blocks) => blocks
                            .iter()
                            .filter_map(|block| match block {
                                WireContentBlock::Text { text } => Some(text.as_str()),
                                _ => None,
                            })
                            .collect::<Vec<_>>()
                            .join(""),
                    };
                    if !text.is_empty() {
                        let preview = if text.len() > 200 {
                            // Find a valid UTF-8 char boundary at or before byte 200
                            let end = text
                                .char_indices()
                                .map(|(i, _)| i)
                                .take_while(|&i| i <= 200)
                                .last()
                                .unwrap_or(0);
                            format!("{}...", &text[..end])
                        } else {
                            text
                        };
                        lines.push(format!("[tool_result({})]: {preview}", result.tool_use_id));
                    }
                }
            }
        }
    }
    lines.push("[End of forked context]".to_string());
    lines.join("\n")
}

/// Local branch of the placement-switched member history read (DEC-P6E-20/21):
/// the SAME serving semantics as the member host's `ReadMemberHistory` arm
/// (tail addressing, per-page cap) over the local session service, projected
/// through THE shared wire page projection.
async fn local_member_history_page(
    session_service: &dyn super::session_service::MobSessionService,
    session_id: &SessionId,
    generation: u64,
    from_index: Option<u64>,
    limit: Option<u32>,
) -> Result<super::member_history_proxy::MemberHistoryPageDomain, MobError> {
    const LOCAL_HISTORY_PAGE_MAX: usize = 256;
    let requested_limit =
        limit.map(|value| usize::try_from(value).unwrap_or(LOCAL_HISTORY_PAGE_MAX));
    let effective_limit = requested_limit
        .unwrap_or(LOCAL_HISTORY_PAGE_MAX)
        .clamp(1, LOCAL_HISTORY_PAGE_MAX);
    let offset = match (from_index, requested_limit) {
        (Some(index), _) => usize::try_from(index).unwrap_or(usize::MAX),
        (None, Some(tail_limit)) => {
            let view = session_service.read(session_id).await.map_err(|error| {
                MobError::Internal(format!("failed to read member session metadata: {error}"))
            })?;
            view.state
                .message_count
                .saturating_sub(tail_limit.clamp(1, LOCAL_HISTORY_PAGE_MAX))
        }
        (None, None) => 0,
    };
    let page = meerkat_core::service::SessionServiceHistoryExt::read_history(
        session_service,
        session_id,
        meerkat_core::service::SessionHistoryQuery {
            offset,
            limit: Some(effective_limit),
        },
    )
    .await
    .map_err(|error| MobError::Internal(format!("failed to read member history: {error}")))?;
    Ok(super::member_history_proxy::MemberHistoryPageDomain {
        generation,
        page: meerkat_contracts::wire::WireMemberHistoryPageBody::try_from_history_page(&page)
            .map_err(|error| {
                MobError::Internal(format!(
                    "failed to project local member history page: {error}"
                ))
            })?,
        // The local branch IS the placement switch's local arm (ADJ-P7-2):
        // the page was served from the controlling host's own store.
        placement: None,
        provenance: meerkat_contracts::wire::WireProjectionProvenance::ControllingHostVerified,
    })
}

pub(super) struct PendingSpawn {
    pub(super) profile_name: ProfileName,
    pub(super) agent_identity: AgentIdentity,
    pub(super) admitted_bridge_session_id: SessionId,
    pub(super) prompt: ContentInput,
    pub(super) initial_turn_prompt: Option<ContentInput>,
    pub(super) runtime_mode: crate::MobRuntimeMode,
    pub(super) labels: std::collections::BTreeMap<String, String>,
    pub(super) owner_bridge_session_id: Option<SessionId>,
    pub(super) auto_wire_parent: bool,
    /// Peer wiring to restore after respawn completes.
    pub(super) restore_wiring: Option<RestoreWiringPlan>,
    /// Exact old incarnation for a respawn replacement. Operation identity is
    /// independent of whether the saved graph is empty: a zero-edge placed
    /// respawn still owns a preservation hold that every terminal path must
    /// resolve or durably abandon.
    respawn_origin: Option<RespawnOrigin>,
    /// Effective profile override from `SpawnTooling::Profile` resolution.
    /// Persisted in the roster so respawn/restore can use it.
    pub(super) effective_profile_override: Option<crate::profile::Profile>,
    /// Field-scoped model override reapplied over the current role profile.
    pub(super) effective_model_override: Option<String>,
    /// Objective causality inherited from the spawning turn.
    pub(super) objective_id: Option<meerkat_core::interaction::ObjectiveId>,
    /// Per-spawn external-tool overlay carried to the finalize commit so the
    /// actor retention map is updated in the same block as the roster insert.
    pub(super) per_spawn_external_tools: Option<Arc<dyn AgentToolDispatcher>>,
    pub(super) authorized_profile_material: AuthorizedSpawnProfileMaterial,
    pub(super) continuity_intent: super::handle::SpawnContinuityIntent,
    pub(super) progress: Arc<std::sync::Mutex<PendingSpawnProgress>>,
    /// External peer id whose recipient trust the provisioner installs ahead
    /// of bind/authorize terminality during this provision. Recorded as a
    /// MobMachine `pending_recipient_trust` obligation at enqueue; resolved
    /// (provision succeeded — terminality confirmed) or rolled back
    /// (provision failed — the provisioner already removed newly installed
    /// trust) when the provision result lands. `None` for session-backed
    /// members, which install no bridge recipient trust.
    pub(super) pending_recipient_trust_peer_id: Option<String>,
    /// Honest spawn-exec observations threaded into the ladder open
    /// (DEC-P3-10; replaces the former hardwired-false block).
    pub(super) observations: SpawnExecObservations,
    /// Remote (host-materialized) spawn facts opened at enqueue; `None`
    /// for every local/external path.
    pub(super) remote: Option<Box<RemoteSpawnExec>>,
    pub(super) reply_tx: oneshot::Sender<Result<super::handle::MemberSpawnReceipt, MobError>>,
}

/// Provisioning material that is cheap enough to prepare while the actor owns
/// command execution, or a durable-resume recipe whose snapshot load and agent
/// config build must run after the machine has reserved the pending spawn.
///
/// The deferred variant is intentionally session-backed only. External
/// bindings establish recipient-trust obligations before provisioning, so
/// widening their pre-provision cancellation window needs separate machine
/// semantics rather than sharing this optimization implicitly.
enum SpawnProvisionInput {
    Ready(ProvisionMemberRequest),
    DeferredResume(Box<DeferredResumeProvision>),
}

struct DeferredResumeProvision {
    definition: Arc<MobDefinition>,
    profile_name: ProfileName,
    agent_identity: AgentIdentity,
    profile: crate::profile::Profile,
    external_tools: Option<Arc<dyn AgentToolDispatcher>>,
    context: Option<serde_json::Value>,
    labels: Option<std::collections::BTreeMap<String, String>>,
    additional_instructions: Option<Vec<String>>,
    shell_env: Option<std::collections::HashMap<String, String>>,
    inherited_tool_filter: Option<meerkat_core::InheritedToolVisibilityAuthority>,
    tool_access_policy: Option<meerkat_core::ops::ToolAccessPolicy>,
    system_prompt_override: Option<super::handle::SpawnSystemPromptOverride>,
    resume_id: SessionId,
    prompt: ContentInput,
    budget_limits: Option<meerkat_core::BudgetLimits>,
    keep_alive: bool,
    default_llm_client: Option<Arc<dyn LlmClient>>,
    binding: crate::RuntimeBinding,
    peer_name: String,
    owner_bridge_session_id: Option<SessionId>,
    ops_registry: Option<Arc<dyn meerkat_core::ops_lifecycle::OpsLifecycleRegistry>>,
    generated_self_owned_operation_owner: Option<SessionId>,
}

impl SpawnProvisionInput {
    fn binding(&self) -> &crate::RuntimeBinding {
        match self {
            Self::Ready(request) => &request.binding,
            Self::DeferredResume(deferred) => &deferred.binding,
        }
    }

    fn admitted_bridge_session_id(&mut self) -> SessionId {
        match self {
            Self::Ready(request) => admit_bridge_session_for_spawn(&mut request.create_session),
            Self::DeferredResume(deferred) => deferred.resume_id.clone(),
        }
    }

    fn install_generated_self_owned_operation_owner(
        &mut self,
        generated_owner: &AuthorizedMobSpawnStart,
    ) -> Result<(), MobError> {
        match self {
            Self::Ready(request) => {
                MobActor::apply_generated_self_owned_operation_owner(request, generated_owner)
            }
            Self::DeferredResume(deferred) => {
                if matches!(deferred.binding, crate::RuntimeBinding::Session)
                    && deferred.owner_bridge_session_id.is_none()
                    && deferred.ops_registry.is_none()
                {
                    deferred.generated_self_owned_operation_owner =
                        Some(generated_owner.owner_session_id().clone());
                }
                Ok(())
            }
        }
    }

    async fn into_request(
        self,
        session_service: Arc<dyn MobSessionService>,
    ) -> Result<ProvisionMemberRequest, MobError> {
        match self {
            Self::Ready(request) => Ok(request),
            Self::DeferredResume(deferred) => deferred.into_request(session_service).await,
        }
    }
}

impl DeferredResumeProvision {
    async fn into_request(
        self: Box<Self>,
        session_service: Arc<dyn MobSessionService>,
    ) -> Result<ProvisionMemberRequest, MobError> {
        let Self {
            definition,
            profile_name,
            agent_identity,
            profile,
            external_tools,
            context,
            labels,
            additional_instructions,
            shell_env,
            inherited_tool_filter,
            tool_access_policy,
            system_prompt_override,
            resume_id,
            prompt,
            budget_limits,
            keep_alive,
            default_llm_client,
            binding,
            peer_name,
            owner_bridge_session_id,
            ops_registry,
            generated_self_owned_operation_owner,
        } = *self;

        let stored_session = match session_service
            .load_persisted_session(&resume_id)
            .await
            .map_err(MobError::from)?
        {
            Some(session) => session,
            None => session_service
                .load_revivable_retired_session(&resume_id)
                .await
                .map_err(MobError::from)?
                .ok_or_else(|| {
                    MobError::Internal(format!(
                        "missing durable session snapshot for '{resume_id}'"
                    ))
                })?,
        };

        let mut config = build::build_resumed_agent_config(build::BuildResumedAgentConfigParams {
            base: build::BuildAgentConfigParams {
                mob_id: &definition.id,
                profile_name: &profile_name,
                agent_identity: &agent_identity,
                profile: &profile,
                definition: &definition,
                external_tools,
                context,
                labels,
                additional_instructions,
                shell_env,
                mob_tool_authority_context: None,
                inherited_tool_filter,
                tool_access_policy,
                system_prompt_override,
            },
            expected_session_id: &resume_id,
            resumed_session: stored_session,
        })
        .await?;
        config.keep_alive = keep_alive;
        if let Some(client) = default_llm_client {
            config.llm_client_override = Some(client);
        }

        let create_session = build::to_create_session_request(&config, prompt);
        let mut request = ProvisionMemberRequest {
            create_session: with_spawn_budget_limits(create_session, budget_limits),
            session_origin: super::provisioner::ProvisionSessionOrigin::ResumedDurable,
            binding,
            peer_name,
            owner_bridge_session_id,
            ops_registry,
            generated_self_owned_operation_owner,
            runtime_revival_intent: super::provisioner::RuntimeRevivalIntent::None,
        };
        let materialized_session_id = admit_bridge_session_for_spawn(&mut request.create_session);
        if materialized_session_id != resume_id {
            return Err(MobError::Internal(format!(
                "durable resume preparation changed session id from '{resume_id}' to '{materialized_session_id}'"
            )));
        }
        Ok(request)
    }
}

/// Incarnation-scoped MobMachine verdict for the pending-spawn mechanics of a
/// public retire request. This is a local mirror of exactly one generated
/// structural effect; it carries no independently derived roster truth.
#[derive(Debug, Clone, PartialEq, Eq)]
enum RetirePendingSpawnVerdict {
    CancelCommittedIncarnation {
        agent_runtime_id: mob_dsl::AgentRuntimeId,
        generation: mob_dsl::Generation,
        pending_spawn_session_id: mob_dsl::SessionId,
    },
    CommittedIncarnationWithoutPendingSpawn {
        agent_runtime_id: mob_dsl::AgentRuntimeId,
        generation: mob_dsl::Generation,
    },
    PreservePendingSpawnForAbsentIdentity,
}

#[derive(Debug, Default)]
pub(super) struct PendingSpawnProgress {
    pub(super) bridge_session_id: Option<meerkat_core::types::SessionId>,
    pub(super) operation_id: Option<meerkat_core::ops::OperationId>,
}

/// Honest spawn-exec observations (DEC-P3-10): a pure function over the
/// destructured spec + resolved profile, computed ONCE at the spawn
/// destructure and threaded as a value into every `BeginSpawnExec`
/// construction. The machine DECIDES; these are shell observations only.
#[derive(Clone, Debug, Default)]
pub(super) struct SpawnExecObservations {
    /// EXPLICIT resolved `profile.tools.workgraph`, captured BEFORE
    /// `open_profile_tool_categories_for_inherited_filter` (ADJ-6: an
    /// inherited-open forced value never sets it).
    pub(super) workgraph_required: bool,
    pub(super) rust_bundles_present: bool,
    pub(super) per_spawn_external_tools_present: bool,
    pub(super) host_surface_mcp_allowlist_present: bool,
    pub(super) inherited_tool_filter_present: bool,
    pub(super) shell_env_present: bool,
    pub(super) mcp_stdio_env_present: bool,
    pub(super) mcp_http_headers_present: bool,
    pub(super) memory_required: bool,
    pub(super) mcp_required: bool,
    /// Remote resume target (launch `Resume` + placement); `None` locally.
    pub(super) resume_session_id: Option<SessionId>,
}

/// Facts for a REMOTE (host-materialized) spawn opened at enqueue time.
/// The machine already holds the tuple from `BeginSpawnExecRemote`; the
/// finalize path re-uses it (never re-mints).
#[derive(Clone, Debug)]
pub(super) struct RemoteSpawnExec {
    pub(super) placed_spawn_id: crate::ids::PlacedSpawnId,
    pub(super) placement: mob_dsl::HostId,
    pub(super) generation: crate::ids::Generation,
    pub(super) fence_token: crate::ids::FenceToken,
    pub(super) resolved_spec_digest: String,
    /// Exact pending carrier durably inserted before bridge dispatch.  This
    /// witness is retained across the round-trip so lost reads cannot weaken
    /// commit or cleanup into identity-only mutations.
    pub(super) pending_carrier: crate::store::MobPlacedSpawnCarrierRecord,
}

/// Remote finalize carrier: the enqueue-time facts plus the transport-
/// validated materialize ack.
struct RemoteSpawnFinalize {
    placed_spawn_id: crate::ids::PlacedSpawnId,
    #[allow(dead_code)]
    placement: mob_dsl::HostId,
    resolved_spec_digest: String,
    pending_carrier: crate::store::MobPlacedSpawnCarrierRecord,
    ack: Box<super::provisioner::MaterializedMemberAck>,
}

/// Result of the remote pre-commit failure choreography.  Recipient-trust
/// rollback is legal only when the exact remote attempt has been released (or
/// proven absent) and its durable carrier cleanup completed.
struct RemoteSpawnFailureOutcome {
    error: MobError,
    cleanup_completed: bool,
}

fn observe_spawn_exec_facts(
    profile: &crate::profile::Profile,
    explicit_workgraph: bool,
    per_spawn_external_tools_present: bool,
    shell_env: Option<&std::collections::HashMap<String, String>>,
    inherited_tool_filter_present: bool,
    resume_session_id: Option<SessionId>,
) -> SpawnExecObservations {
    let mcp_stdio_env_present = profile.tools.mcp_servers.iter().any(|server| {
        matches!(
            &server.transport,
            meerkat_core::mcp_config::McpTransportConfig::Stdio(stdio) if !stdio.env.is_empty()
        )
    });
    let mcp_http_headers_present = profile.tools.mcp_servers.iter().any(|server| {
        matches!(
            &server.transport,
            meerkat_core::mcp_config::McpTransportConfig::Http(http) if !http.headers.is_empty()
        )
    });
    SpawnExecObservations {
        workgraph_required: explicit_workgraph,
        rust_bundles_present: !profile.tools.rust_bundles.is_empty(),
        per_spawn_external_tools_present,
        host_surface_mcp_allowlist_present: !profile.tools.mcp.is_empty(),
        inherited_tool_filter_present,
        shell_env_present: shell_env.is_some_and(|env| !env.is_empty()),
        mcp_stdio_env_present,
        mcp_http_headers_present,
        memory_required: profile.tools.memory,
        mcp_required: !profile.tools.mcp_servers.is_empty(),
        resume_session_id,
    }
}

/// DEC-P3-7: the ONE owner of `RecordMemberMaterializationFailure.kind`
/// strings — the wire cause's serde tag for typed rejects, reserved shell
/// classes for transport faults. Total: an unclassifiable error carries its
/// failure class, never an empty/absent kind.
fn materialization_failure_kind(error: &MobError) -> String {
    match error {
        MobError::BridgeCommandRejected { cause, .. } => bridge_rejection_cause_tag(cause),
        MobError::BridgeRequestTimedOut { .. } => "materialize_timeout".to_string(),
        MobError::CommsError(_) => "materialize_send_failed".to_string(),
        other => format!("unclassified:{:?}", other.failure_class()),
    }
}

/// Snake-case serde tag of a typed wire rejection cause (e.g.
/// `model_unresolvable`, `stale_fence`). Uses the cause's own serde
/// rendering so the string can never drift from the wire vocabulary.
fn bridge_rejection_cause_tag(cause: &super::bridge_protocol::BridgeRejectionCause) -> String {
    match serde_json::to_value(cause) {
        Ok(serde_json::Value::String(tag)) => tag,
        Ok(serde_json::Value::Object(map)) => map
            .get("cause")
            .and_then(serde_json::Value::as_str)
            .map(str::to_string)
            .unwrap_or_else(|| format!("unclassified_cause:{cause:?}")),
        _ => format!("unclassified_cause:{cause:?}"),
    }
}

#[must_use = "mob spawn start authority must be consumed by pending spawn insertion"]
struct AuthorizedMobSpawnStart {
    generated_can_start: generated_mob_command_capabilities::CommandPlanKind,
    generated_owner: generated_mob_command_capabilities::CommandPlanKind,
    agent_identity: AgentIdentity,
    session_id: SessionId,
}

#[must_use = "started mob spawn authority must be consumed by PendingSpawnLineage insertion"]
struct AuthorizedMobSpawnStarted {
    generated_owner: generated_mob_command_capabilities::CommandPlanKind,
    generated_started: generated_mob_command_capabilities::CommandPlanKind,
    agent_identity: AgentIdentity,
    session_id: SessionId,
}

#[must_use = "mob spawn completion authority must be observed by pending spawn completion"]
struct AuthorizedMobSpawnCompleted {
    generated_plan: generated_mob_command_capabilities::CommandPlanKind,
    generated_effect: generated_mob_command_capabilities::CommandPlanKind,
    agent_identity: AgentIdentity,
}

impl AuthorizedMobSpawnStart {
    fn owner_session_id(&self) -> &SessionId {
        debug_assert_eq!(
            self.generated_can_start,
            generated_mob_command_capabilities::CommandPlanKind::CanStartSpawn
        );
        debug_assert_eq!(
            self.generated_owner,
            generated_mob_command_capabilities::CommandPlanKind::AuthorizedMobSpawnStart
        );
        &self.session_id
    }

    fn start(self, pending: &PendingSpawn) -> Result<AuthorizedMobSpawnStarted, MobError> {
        debug_assert_eq!(
            self.generated_can_start,
            generated_mob_command_capabilities::CommandPlanKind::CanStartSpawn
        );
        debug_assert_eq!(
            self.generated_owner,
            generated_mob_command_capabilities::CommandPlanKind::AuthorizedMobSpawnStart
        );
        if pending.agent_identity != self.agent_identity
            || pending.admitted_bridge_session_id != self.session_id
        {
            return Err(MobError::Internal(format!(
                "MobMachine StageSpawn authority for '{}' / '{}' did not match pending spawn '{}' / '{}'",
                self.agent_identity,
                self.session_id,
                pending.agent_identity,
                pending.admitted_bridge_session_id
            )));
        }
        Ok(AuthorizedMobSpawnStarted {
            generated_owner: self.generated_owner,
            generated_started: generated_mob_command_capabilities::CommandPlanKind::SpawnStarted,
            agent_identity: self.agent_identity,
            session_id: self.session_id,
        })
    }
}

