    #[test]
    fn proven_no_effect_bind_abort_allows_new_operation_at_same_generation() {
        let mob_id = MobId::from("host-bind-no-effect-retry");
        let event = |cursor, kind| MobEvent {
            cursor,
            timestamp: Utc::now(),
            mob_id: mob_id.clone(),
            kind,
        };
        let first = meerkat_core::time_compat::new_uuid_v7().to_string();
        let retry = meerkat_core::time_compat::new_uuid_v7().to_string();
        let mut request = bind_anchor_request();
        request.binding_generation = 1;
        let mut authority = bind_anchor_authority();
        authority.binding_generation = 1;
        let history = vec![
            event(
                1,
                MobEventKind::RemoteHostBindStarted {
                    operation_id: first.clone(),
                    request: request.clone(),
                },
            ),
            event(
                2,
                MobEventKind::RemoteHostBindAbortedNoEffect {
                    operation_id: first.clone(),
                    host_id: request.host_id.clone(),
                    authority_epoch: request.authority_epoch,
                    binding_generation: request.binding_generation,
                },
            ),
            event(
                3,
                MobEventKind::RemoteHostBindStarted {
                    operation_id: retry.clone(),
                    request: request.clone(),
                },
            ),
            event(
                4,
                MobEventKind::RemoteHostBindConfirmed {
                    operation_id: retry.clone(),
                    authority,
                },
            ),
            event(
                5,
                MobEventKind::RemoteHostBindCompleted {
                    operation_id: retry,
                    host_id: request.host_id.clone(),
                    authority_epoch: request.authority_epoch,
                    binding_generation: request.binding_generation,
                },
            ),
        ];
        validate_host_authority_anchor_epoch_boundaries(&history)
            .expect("provable pre-write abort may retry the Requested generation with a new op id");

        let revoke = meerkat_core::time_compat::new_uuid_v7().to_string();
        let late_retry = meerkat_core::time_compat::new_uuid_v7().to_string();
        let mut late = history;
        late.extend([
            event(
                6,
                MobEventKind::RemoteHostRevokeStarted {
                    operation_id: revoke.clone(),
                    host_id: request.host_id.clone(),
                    epoch: request.authority_epoch,
                    binding_generation: 1,
                },
            ),
            event(
                7,
                MobEventKind::RemoteHostRevokeConfirmed {
                    operation_id: revoke.clone(),
                    host_id: request.host_id.clone(),
                    epoch: request.authority_epoch,
                    binding_generation: 1,
                },
            ),
            event(
                8,
                MobEventKind::RemoteHostRevokeCompleted {
                    operation_id: revoke,
                    host_id: request.host_id.clone(),
                    epoch: request.authority_epoch,
                    binding_generation: 1,
                },
            ),
            event(
                9,
                MobEventKind::RemoteHostBindAbortedNoEffect {
                    operation_id: first,
                    host_id: request.host_id.clone(),
                    authority_epoch: request.authority_epoch,
                    binding_generation: 1,
                },
            ),
            event(
                10,
                MobEventKind::RemoteHostBindStarted {
                    operation_id: late_retry,
                    request,
                },
            ),
        ]);
        assert!(
            validate_host_authority_anchor_epoch_boundaries(&late)
                .expect_err("late duplicate abort cannot reopen a remotely consumed generation")
                .to_string()
                .contains("does not advance")
        );
    }

