    #[cfg(feature = "runtime-adapter")]
    #[test]
    fn kickoff_finalization_failure_never_projects_started() {
        let identity = AgentIdentity::from("worker-finalization-failure");

        for (error, expected_error) in [
            (
                meerkat_core::TurnErrorMetadata::runtime_apply_failure(
                    "durable transcript commit failed",
                ),
                "durable transcript commit failed",
            ),
            (
                meerkat_core::TurnErrorMetadata {
                    detail: None,
                    ..meerkat_core::TurnErrorMetadata::runtime_apply_failure("discarded")
                },
                "turn finalization failed",
            ),
        ] {
            let input = kickoff_resolution_input(
                &identity,
                meerkat_runtime::completion::CompletionOutcome::CompletedWithFinalizationFailure {
                    error,
                },
            );
            match input {
                mob_dsl::MobMachineInput::KickoffResolveFailed { member_id, error } => {
                    assert_eq!(member_id.0, identity.as_str());
                    assert_eq!(error, expected_error);
                }
                other => {
                    panic!("non-durable kickoff completion must resolve Failed, got {other:?}")
                }
            }
        }
    }

    #[test]
    fn callback_pending_is_settled_for_the_kickoff_barrier() {
        let pending = mob_dsl::AgentIdentity::from("pending-member");
        let starting = mob_dsl::AgentIdentity::from("starting-member");
        let callback_pending = mob_dsl::AgentIdentity::from("callback-member");
        let mut state = mob_dsl::MobMachineAuthority::new().state().clone();
        state.member_kickoff_pending.insert(pending.clone());
        state.member_kickoff_starting.insert(starting.clone());
        state
            .member_kickoff_callback_pending
            .insert(callback_pending.clone());

        let unresolved = unresolved_kickoff_member_ids(&state);
        assert!(unresolved.contains(&pending.0));
        assert!(unresolved.contains(&starting.0));
        assert!(
            !unresolved.contains(&callback_pending.0),
            "callback-pending is a one-shot interaction terminal, not an unresolved kickoff"
        );
        assert_eq!(
            state
                .kickoff_material_for_member_id(&callback_pending.0)
                .expect("callback phase remains projected")
                .phase,
            mob_dsl::KickoffPhase::CallbackPending,
            "settling the barrier must not erase the external-fulfillment diagnostic"
        );
    }

